def least_frequent_word(s):
    if not s:
        return ''
    word_freq = {}
    for word in s.split():
        word_freq[word] = word_freq.get(word, 0) + 1
    min_count = min(word_freq.values())
    least_frequent_words = [word for word, count in word_freq.items() if count == min_count]
    least_frequent_words.sort()
    return least_frequent_words[0]
